```python
def separate_paren_groups(paren_string: str) -> List[str]:
    paren_string = paren_string.replace(" ", "")
    result = []
    stack = []
    current_group = []

    for char in paren_string:
        if char == '(':
            if not stack:
                current_group = []
            stack.append(char)
            current_group.append(char)
        elif char == ')':
            if stack:
                stack.pop()
                current_group.append(char)
                if not stack:
                    result.append(''.join(current_group))

    return result
```

```python
def separate_paren_groups(paren_string: str) -> List[str]:
    groups = []
    current_group = []
    balance = 0

    for char in paren_string.replace(" ", ""):
        if char == '(':
            if balance == 0 and current_group:
                groups.append(''.join(current_group))
                current_group = []
            current_group.append(char)
            balance += 1
        elif char == ')':
            current_group.append(char)
            balance -= 1

        if balance == 0 and current_group:
            groups.append(''.join(current_group))
            current_group = []

    return groups
```

```python
def separate_paren_groups(paren_string: str) -> List[str]:
    paren_string = paren_string.replace(' ', '')
    groups = []
    balance = 0
    current_group = []

    for char in paren_string:
        if char == '(':
            if balance == 0 and current_group:
                groups.append(''.join(current_group))
                current_group = []
            current_group.append(char)
            balance += 1
        elif char == ')':
            current_group.append(char)
            balance -= 1
            if balance == 0:
                groups.append(''.join(current_group))
                current_group = []

    if current_group:
        groups.append(''.join(current_group))

    return groups
```

